// Polished per-muscle illustration icons (licensed flat-art set, highlight recolored to the app
// accent). Keyed by lowercased muscle group. Muscles without a dedicated icon (forearms, neck,
// full body, cardio, yoga) fall back to the code-drawn figure below.
const MUSCLE_ICONS = {"chest": "data:image/png;base64,", "shoulders": "data:image/png;base64,", "biceps": "data:image/png;base64,", "forearms": "data:image/png;base64,", "triceps": "data:image/png;base64,", "traps": "data:image/png;base64,", "back": "data:image/png;base64,", "lats": "data:image/png;base64,", "rear delts": "data:image/png;base64,", "quads": "data:image/png;base64,", "hamstrings": "data:image/png;base64,", "glutes": "data:image/png;base64,", "calves": "data:image/png;base64,", "core": "data:image/png;base64,", "abs": "data:image/png;base64,", "obliques": "data:image/png;base64,"};
function MuscleIcon({ muscle = "", name = "", size = 28, C }) {
  let m = (muscle || "").toLowerCase().split("/")[0].trim();
  // If the stored muscle is missing or has no illustration (common for free-typed exercise names
  // that aren't in the library), resolve the muscle from the exercise name instead.
  const hasIcon = (mm) => (typeof MUSCLE_ICONS !== "undefined") && MUSCLE_ICONS[mm];
  if ((!m || !hasIcon(m)) && name) {
    const r = (typeof getMuscle === "function" && getMuscle(name)) || (typeof resolveMuscle === "function" && resolveMuscle(name));
    if (r) m = (r || "").toLowerCase().split("/")[0].trim();
  }
  const isDark = C?.isDark ?? (C?.bg === "#0a0a0c");
  // Use the polished illustration icon when this muscle has one.
  const rasterSrc = (typeof MUSCLE_ICONS !== "undefined") && MUSCLE_ICONS[m];
  if (rasterSrc) {
    const ringR = isDark ? "rgba(139,92,246,0.28)" : "rgba(124,58,237,0.18)";
    const tintR = isDark ? "rgba(139,92,246,0.14)" : "rgba(124,58,237,0.08)";
    return (
      <div style={{ width:size, height:size, borderRadius:Math.round(size*0.28), background:tintR, border:`1px solid ${ringR}`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, overflow:"hidden" }}>
        <img src={rasterSrc} alt={muscle} style={{ width:"86%", height:"86%", objectFit:"contain" }}/>
      </div>
    );
  }
  const accent = isDark ? (C?.accent || "#8b5cf6") : (C?.accent || "#7c3aed");
  const bodyFill = isDark ? "#3d3d46" : "#c5cad3";
  const stroke = isDark ? "#2b2b32" : "#aab1bd";
  const tint = isDark ? "rgba(139,92,246,0.14)" : "rgba(124,58,237,0.08)";
  const ring = isDark ? "rgba(139,92,246,0.28)" : "rgba(124,58,237,0.18)";

  let inner;
  if (m === "cardio") {
    inner = <svg width="58%" viewBox="0 0 40 56" fill={accent}><path d="M20 44s-13-8.5-13-18C7 20 10.5 16 15 16c2.6 0 4.4 1.4 5 2.7.6-1.3 2.4-2.7 5-2.7 4.5 0 8 4 8 10 0 9.5-13 18-13 18z"/></svg>;
  } else if (m === "yoga") {
    inner = <svg width="58%" viewBox="0 0 40 56" fill="none" stroke={accent} strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"><circle cx="20" cy="16" r="4.5"/><path d="M9 42c4-6 8-8 11-8s7 2 11 8M8 42h24"/></svg>;
  } else if (m === "full body" || m === "") {
    inner = <svg width="80%" viewBox="0 0 40 56">{_MI_BODY(accent, accent)}</svg>;
  } else {
    const hl = _MI_HL[m] || null;
    inner = <svg width="80%" viewBox="0 0 40 56">
      {_MI_BODY(bodyFill, stroke)}
      {hl && <g fill={accent} dangerouslySetInnerHTML={{ __html: hl }}/>}
    </svg>;
  }
  return (
    <div style={{
      width:size, height:size, borderRadius:Math.round(size*0.28),
      background:tint, border:`1px solid ${ring}`,
      display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, overflow:"hidden",
    }}>{inner}</div>
  );
}

let _setToast = null;
function toast(msg, type = "info") {
  if (_setToast) _setToast({ msg, type, id: Date.now() });
}
function ToastHost() {
  const [t, setT] = useState(null);
  _setToast = setT;
  useEffect(() => {
    if (!t) return;
    const id = setTimeout(() => setT(null), 2800);
    return () => clearTimeout(id);
  }, [t?.id]);
  if (!t) return null;
  const bg = t.type === "error" ? "#ef4444" : t.type === "success" ? "#22c55e" : "#6d28d9";
  return (
    <div style={{
      position:"fixed", bottom:90, left:"50%", transform:"translateX(-50%)",
      background:bg, color:"#fff", borderRadius:20, padding:"10px 20px",
      fontSize:13, fontWeight:600, zIndex:999, whiteSpace:"nowrap",
      boxShadow:"0 4px 20px rgba(0,0,0,0.2)", fontFamily:F,
      animation:"fadeInUp 0.2s ease"
    }}>
      {t.msg}
      <style>{`@keyframes fadeInUp{from{opacity:0;transform:translate(-50%,12px)}to{opacity:1;transform:translate(-50%,0)}}`}</style>
    </div>
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// SET TYPES
// ═════════════════════════════════════════════════════════════════════════════
const SET_TYPES = [
  { id:"normal",  label:"Normal",   color:"#8e8e93", short:"N" },
  { id:"warmup",  label:"Warm-up",  color:"#f97316", short:"W" },
  { id:"drop",    label:"Drop Set", color:"#a855f7", short:"D" },
  { id:"failure", label:"Failure",  color:"#ef4444", short:"F" },
];

// ═════════════════════════════════════════════════════════════════════════════
// UTILITIES
// ═════════════════════════════════════════════════════════════════════════════
const uid = () => Math.random().toString(36).slice(2,10);

// Generate a friendly shareable code like "IGNITE-X9K2"
// Excludes ambiguous chars: 0, O, 1, I, L
const CODE_CHARS = "ABCDEFGHJKMNPQRSTUVWXYZ23456789";
function generateShareCode(prefix = "IGNITE") {
  let suffix = "";
  for (let i = 0; i < 4; i++) suffix += CODE_CHARS[Math.floor(Math.random() * CODE_CHARS.length)];
  return `${prefix}-${suffix}`;
}
function normalizeShareCode(input) {
  if (!input) return "";
  return String(input).toUpperCase().replace(/[^A-Z0-9-]/g, "").trim();
}
const timeAgo = ts => {
  const s = Math.floor((Date.now()-ts)/1000);
  if (s < 60) return `${s}s`;
  if (s < 3600) return `${Math.floor(s/60)}m`;
  if (s < 86400) return `${Math.floor(s/3600)}h`;
  if (s < 86400*7) return `${Math.floor(s/86400)}d`;
  return new Date(ts).toLocaleDateString();
};
const fmtTime = s => `${String(Math.floor(s/60)).padStart(2,"0")}:${String(s%60).padStart(2,"0")}`;
const fmtVol = (v, u) => v >= 1000 ? `${(v/1000).toFixed(1)}k ${u}` : `${v} ${u}`;

// Small rest-timer chip for the top bar. Reads the active rest from localStorage ("seshd_rest")
// — which WorkoutTracker writes — and recomputes the remaining seconds from startedAt so it's
// accurate on any tab without touching WorkoutTracker's timer logic. Renders nothing unless a
// rest is actively running. Tapping it calls onTap (used to jump back to the workout tab).
function RestChip({ C, onTap }) {
  const [secs, setSecs] = useState(null);
  useEffect(() => {
    const read = () => {
      try {
        const raw = localStorage.getItem("seshd_rest");
        if (!raw) { setSecs(null); return; }
        const r = JSON.parse(raw);
        if (!r?.running || !r?.startedAt || !r?.total) { setSecs(null); return; }
        const remaining = Math.max(0, r.total - Math.floor((Date.now() - r.startedAt) / 1000));
        setSecs(remaining > 0 ? remaining : null);
      } catch { setSecs(null); }
    };
    read();
    const id = setInterval(read, 1000);
    return () => clearInterval(id);
  }, []);
  if (secs == null) return null;
  const low = secs <= 10;
  return (
    <button onClick={onTap} aria-label="Rest timer — tap to return to workout" style={{
      display:"flex", alignItems:"center", gap:5, padding:"4px 9px", borderRadius:999,
      background: low ? "#EF444418" : C.accentSoft || `${C.accent}18`, border:`1px solid ${low ? "#EF4444" : C.accent}55`,
      color: low ? "#EF4444" : C.accent, fontSize:12, fontWeight:700, fontFamily:MONO, cursor:"pointer", lineHeight:1,
    }}>
      <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><circle cx="12" cy="13" r="8"/><path d="M12 9v4M12 2h0M9 2h6"/></svg>
      {fmtTime(secs)}
    </button>
  );
}


// Split comment/caption text into React fragments, highlighting @username mentions
// in the accent color when the username matches a known user. If onUserClick is provided,
// the mention is clickable and opens the user's profile.
function renderWithMentions(text, store, C, onUserClick) {
  if (!text) return text;
  const usersByHandle = new Map();
  (store?.users || []).forEach(u => { if (u.username) usersByHandle.set(u.username.toLowerCase(), u); });
  const parts = text.split(/(@[a-zA-Z0-9_]+)/g);
  return parts.map((part, i) => {
    if (part[0] === "@") {
      const handle = part.slice(1).toLowerCase();
      const u = usersByHandle.get(handle);
      if (u) {
        return (
          <span
            key={i}
            onClick={(e) => { if (onUserClick) { e.stopPropagation(); onUserClick(u.id); } }}
            style={{ color: C.accent, fontWeight: 600, cursor: onUserClick ? "pointer" : "default" }}
          >{part}</span>
        );
      }
    }
    return part;
  });
}

// Pull the set of valid @mentioned user IDs out of a piece of text (for notifications).
function extractMentions(text, users) {
  if (!text) return [];
  const handles = (text.match(/@([a-zA-Z0-9_]+)/g) || []).map(m => m.slice(1).toLowerCase());
  if (handles.length === 0) return [];
  const ids = [];
  (users || []).forEach(u => {
    if (u.username && handles.includes(u.username.toLowerCase())) ids.push(u.id);
  });
  return [...new Set(ids)];
}

// Local-date key YYYY-MM-DD. MUST use local components, not toISOString() (which is
// UTC and shifts the day for users in positive-UTC timezones, misaligning the
// heatmap/calendar and day-grouping of workouts).
const dKey = (d = new Date()) => {
  const dt = (d instanceof Date) ? d : new Date(d);
  return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,"0")}-${String(dt.getDate()).padStart(2,"0")}`;
};

const LBS_TO_KG = 0.453592;

// Reusable plate-per-side calculator
// Returns array of { p, count } or null if unachievable
const BARBELL_BAR_LBS = 45;
const BARBELL_BAR_KG = 20;
const PLATES_LBS_LIST = [45, 35, 25, 10, 5, 2.5];
const PLATES_KG_LIST = [25, 20, 15, 10, 5, 2.5, 1.25];
const PLATE_COLOR_MAP = { 45:"#ef4444", 35:"#3b82f6", 25:"#22c55e", 10:"#f59e0b", 5:"#8b5cf6", 2.5:"#ec4899", 20:"#3b82f6", 15:"#22c55e", 1.25:"#ec4899" };
// Detect exercises where weight is loaded on ONE end of the bar only (T-bar row, landmine
// variants). For these, the "bar" doesn't add resistance — the user enters total plate
// weight directly, and we show plates as a single stack, not "per side."
function isOneSidedBarbell(name) {
  if (!name) return false;
  return /\bt-?bar\b|\blandmine\b/i.test(name);
}

function calcPlatesPerSide(totalWeight, unit, oneSided = false) {
  const t = parseFloat(totalWeight);
  const plates = unit === "kg" ? PLATES_KG_LIST : PLATES_LBS_LIST;
  if (oneSided) {
    // No bar subtraction, no halving — the entered weight IS the plate weight on one end.
    if (!t || t <= 0) return null;
    let remaining = t;
    const result = [];
    for (const p of plates) {
      const count = Math.floor(remaining / p);
      if (count > 0) {
        result.push({ p, count });
        remaining = Math.round((remaining - p * count) * 1000) / 1000;
      }
    }
    if (!result.length) return null;
    // Attach the un-loadable remainder (per side) so the UI can show "≈ closest" instead of
    // silently giving nothing when the exact weight isn't achievable with standard plates.
    result.leftover = remaining > 0.01 ? remaining : 0;
    return result;
  }
  const bar = unit === "kg" ? BARBELL_BAR_KG : BARBELL_BAR_LBS;
  if (!t || t <= bar) return null;
  let remaining = (t - bar) / 2;
  const result = [];
  for (const p of plates) {
    const count = Math.floor(remaining / p);
    if (count > 0) {
      result.push({ p, count });
      remaining = Math.round((remaining - p * count) * 1000) / 1000;
    }
  }
  if (!result.length) return null;
  // leftover = weight per side that couldn't be made with standard plates (0 if exact).
  result.leftover = remaining > 0.01 ? remaining : 0;
  return result;
}
// Generate warmup sets ramping up to a working weight.
// Returns 4 sets: empty bar, then ~45%, ~65%, ~85% of working weight, each rounded
// to the nearest achievable weight given standard plates. Reps taper as weight rises.
// Used by the opt-in "Add warmup" button on compound barbell lifts.
function generateWarmupSets(workingWeight, unit) {
  const w = parseFloat(workingWeight);
  if (!w || w <= 0) return [];
  const bar = unit === "kg" ? BARBELL_BAR_KG : BARBELL_BAR_LBS;
  // Smallest increment we can actually load (plate × 2 sides)
  const minPlate = unit === "kg" ? 1.25 : 2.5;
  const step = minPlate * 2;
  // Round a target weight to the nearest achievable barbell load (>= bar)
  const roundToBar = (target) => {
    if (target <= bar) return bar;
    const rounded = Math.round((target - bar) / step) * step + bar;
    return Math.max(bar, rounded);
  };
  // Only warm up if the working weight is meaningfully above the bar
  if (w <= bar + step) return [];
  const ramp = [
    { pct: 0, reps: 8 },     // empty bar
    { pct: 0.45, reps: 5 },
    { pct: 0.65, reps: 3 },
    { pct: 0.85, reps: 2 },
  ];
  const sets = [];
  let lastWeight = -1;
  for (const r of ramp) {
    const target = r.pct === 0 ? bar : roundToBar(w * r.pct);
    // Skip if this warmup weight equals the working weight or duplicates the previous step
    if (target >= w || target === lastWeight) continue;
    lastWeight = target;
    sets.push({ id: uid(), weight: String(target), reps: String(r.reps), done: false, type: "warmup" });
  }
  return sets;
}

function cvt(w, from, to) {
  if (!w || from === to) return w;
  const n = parseFloat(w);
  if (isNaN(n)) return w;
  if (from === "lbs" && to === "kg") return Math.round(n * LBS_TO_KG * 10) / 10;
  if (from === "kg" && to === "lbs") return Math.round(n / LBS_TO_KG * 10) / 10;
  return n;
}

function calc1RM(weight, reps) {
  if (!weight || !reps) return null;
  const w = parseFloat(weight), r = parseInt(reps);
  if (isNaN(w) || isNaN(r) || r < 1) return null;
  return Math.round(w * (1 + r / 30));
}

// Get ISO week boundary (Mon 00:00 local) for a given date
function weekStart(d = new Date()) {
  const date = new Date(d);
  date.setHours(0, 0, 0, 0);
  const day = date.getDay(); // 0 (Sun) - 6 (Sat)
  const offset = day === 0 ? 6 : day - 1; // distance back to Monday
  date.setDate(date.getDate() - offset);
  return date;
}
function weekKey(d) {
  const w = weekStart(d);
  return `${w.getFullYear()}-W${String(Math.floor((w.getTime() - new Date(w.getFullYear(), 0, 1).getTime()) / 604800000) + 1).padStart(2, "0")}`;
}

// Streak v2 — "active week" model.
// User has a weekly workout target (default 3). Each week they hit the target counts as "active".
// Streak is # of consecutive active weeks ending in the current or previous week.
// Returns: { count, target, thisWeek, weeksActive, status } where status is "active" | "at-risk" | "lost"
function calcWeeklyStreak(workoutDates, target = 3) {
  const keys = Object.keys(workoutDates || {});
  if (!keys.length) return { count: 0, target, thisWeek: 0, status: "lost" };

  // Group workouts by week key
  const byWeek = {};
  for (const dk of keys) {
    const wk = weekKey(new Date(dk));
    byWeek[wk] = (byWeek[wk] || 0) + 1;
  }

  // Start from the most recent week we have activity in, walk backward
  const now = new Date();
  const thisWeekKey = weekKey(now);
  const thisWeekCount = byWeek[thisWeekKey] || 0;

  // Determine streak: count consecutive active weeks ending in this week OR last week
  // (this week not counted as failure until the week is over)
  let streak = 0;
  let cursor = new Date(now);
  let countingThisWeek = thisWeekCount >= target;

  // Move cursor to start of this week, then iterate weeks
  cursor = weekStart(cursor);
  // Skip this week if it's not yet "made" — only count if hit target OR allow grace
  if (!countingThisWeek) {
    // Don't count this week toward streak yet, but don't break it either — start from last week
    cursor.setDate(cursor.getDate() - 7);
  }

  for (let i = 0; i < 104; i++) { // up to 2 years
    const wk = weekKey(cursor);
    const count = byWeek[wk] || 0;
    if (count >= target) {
      streak++;
      cursor.setDate(cursor.getDate() - 7);
    } else {
      break;
    }
  }

  // Status: active if hit this week, at-risk if last week was active but this week isn't yet
  let status = "lost";
  if (countingThisWeek) status = "active";
  else if (streak > 0) status = "at-risk"; // had a streak going, this week not yet made

  return { count: streak, target, thisWeek: thisWeekCount, status };
}

// Legacy daily-streak helper — kept for components that haven't migrated yet
function calcStreak(workoutDates) {
  const keys = Object.keys(workoutDates||{}).sort().reverse();
  if (!keys.length) return 0;
  const set = new Set(keys);
  let streak = 0;
  const check = new Date(); check.setHours(0,0,0,0);
  for (let i = 0; i < 365; i++) {
    if (set.has(dKey(check))) streak++;
    else if (i > 0) break;
    check.setDate(check.getDate()-1);
  }
  return streak;
}

function getPrev(store, exName, si, unit) {
  // `si` here is the WORKING-set index (warmups excluded). We match it against the
  // previous session's working sets only, so warmups on either side don't misalign
  // the "Previous" column.
  if (si == null || si < 0) return null;
  const dates = Object.keys(store.history||{}).sort().reverse();
  for (const d of dates) {
    const sessions = Object.values(store.history[d]||{});
    for (const sess of sessions) {
      const ex = sess.exercises?.find(e => e.name === exName);
      if (!ex) continue;
      const workingSets = (ex.sets || []).filter(s => s.type !== "warmup");
      const set = workingSets[si];
      if (set?.weight || set?.reps) {
        const su = sess.unit || "lbs";
        return { w: cvt(set.weight||0, su, unit), r: set.reps||0 };
      }
    }
  }
  return null;
}

// Get the most recent COMPLETED session for an exercise (across all sets)
function getLastExerciseSession(store, exName) {
  const dates = Object.keys(store.history||{}).sort().reverse();
  for (const d of dates) {
    const sessions = Object.values(store.history[d]||{});
    for (const sess of sessions) {
      const ex = sess.exercises?.find(e => e.name === exName);
      if (!ex) continue;
      // Filter to WORKING sets only — exclude warmups (their light weight + low reps would
      // otherwise mask real progression and make the engine recommend "same weight, push reps"
      // even when the user actually hit the top of their range on their working sets).
      const doneSets = (ex.sets||[]).filter(s =>
        s.type !== "warmup" &&
        (s.done === true || (s.done === undefined && parseFloat(s.reps) > 0))
      );
      if (doneSets.length > 0) {
        // Days-since needs LOCAL date math (the key is YYYY-MM-DD; constructing a Date
        // from that string parses as UTC midnight, which shifts the day in non-zero
        // timezones and can yield off-by-one daysSince).
        const todayKey = dKey();
        const todayMs = new Date(todayKey + "T12:00:00").getTime();
        const dMs = new Date(d + "T12:00:00").getTime();
        return {
          date: d,
          unit: sess.unit || "lbs",
          sets: doneSets.map(s => ({ w: parseFloat(s.weight)||0, r: parseFloat(s.reps)||0 })),
          daysSince: Math.max(0, Math.floor((todayMs - dMs) / 86400000)),
        };
      }
    }
  }
  return null;
}

// ─── Progress Insights Engine ───────────────────────────────────────────────
// Scans workout history and surfaces the single most compelling TRUE fact about
// the user's recent progress. Returns { icon, headline, sub } or null.
// Everything here is derived from data already on hand — no new tracking needed.
// The whole point: make the user feel their progress, which they often don't notice.
function getProgressInsight(store, unit, returnAll = false) {
  const history = store.history || {};
  const dates = Object.keys(history).sort(); // ascending
  if (dates.length < 2) return null; // need some history to say anything meaningful

  const now = Date.now();
  const DAY = 86400000;
  const candidates = [];

  // Helper: collect all completed (non-warmup) sets for an exercise with their date
  function exerciseSets(exName) {
    const out = [];
    for (const d of dates) {
      for (const sess of Object.values(history[d] || {})) {
        const ex = (sess.exercises || []).find(e => e.name === exName);
        if (!ex) continue;
        const su = sess.unit || "lbs";
        (ex.sets || []).forEach(s => {
          const done = s.done === true || (s.done === undefined && parseFloat(s.reps) > 0);
          if (done && s.type !== "warmup") {
            const w = cvt(parseFloat(s.weight) || 0, su, unit);
            const r = parseFloat(s.reps) || 0;
            // Epley 1RM is only reliable up to ~12 reps. Above that, a burnout/endurance
            // set would inflate the estimate and produce a false "you got stronger" claim,
            // so we don't let those sets define an e1RM for insight purposes.
            const e1rm = (r >= 1 && r <= 12) ? (calc1RM(w, r) || 0) : 0;
            out.push({ date: d, t: new Date(d).getTime(), w, r, e1rm });
          }
        });
      }
    }
    return out;
  }

  // 1. Strength gain on a key lift over the last ~8 weeks (best e1RM then vs now)
  const allExercises = new Set();
  for (const d of dates) {
    for (const sess of Object.values(history[d] || {})) {
      (sess.exercises || []).forEach(e => e.name && allExercises.add(e.name));
    }
  }
  for (const exName of allExercises) {
    const sets = exerciseSets(exName);
    if (sets.length < 4) continue; // need enough data
    const eightWeeksAgo = now - 56 * DAY;
    const older = sets.filter(s => s.t < eightWeeksAgo);
    const recent = sets.filter(s => s.t >= eightWeeksAgo);
    if (!older.length || !recent.length) {
      // Not enough span — compare first quarter vs last quarter of available data
      const q = Math.max(1, Math.floor(sets.length / 4));
      const earlyBest = Math.max(...sets.slice(0, q).map(s => s.e1rm));
      const lateBest = Math.max(...sets.slice(-q).map(s => s.e1rm));
      if (earlyBest > 0 && lateBest > earlyBest) {
        const gain = Math.round(lateBest - earlyBest);
        if (gain >= (unit === "kg" ? 5 : 10)) {
          candidates.push({ key: `strength:${exName}`, priority: 2, icon: "trending", headline: `Your ${exName} is up ${gain} ${unit}`, sub: `Estimated 1-rep max since you started tracking it` });
        }
      }
      continue;
    }
    const olderBest = Math.max(...older.map(s => s.e1rm));
    const recentBest = Math.max(...recent.map(s => s.e1rm));
    if (olderBest > 0 && recentBest > olderBest) {
      const gain = Math.round(recentBest - olderBest);
      if (gain >= (unit === "kg" ? 5 : 10)) {
        candidates.push({ key: `strength:${exName}`, priority: 1, icon: "trending", headline: `Your ${exName} is up ${gain} ${unit}`, sub: `Estimated 1-rep max, recent sessions vs earlier` });
      }
    }
  }

  // 2. Weekly streak milestone
  const ws = calcWeeklyStreak(store.workoutDates || {}, store.weeklyTarget || 3);
  if (ws.count >= 2) {
    candidates.push({ key: `streak:${ws.count}`, priority: ws.count >= 4 ? 1 : 3, icon: "flame", headline: `${ws.count} week streak`, sub: `You've hit your weekly target ${ws.count} weeks running. Keep it alive.` });
  }

  // 3. Biggest-volume week ever (this week vs all prior weeks)
  const volByWeek = {};
  for (const d of dates) {
    for (const sess of Object.values(history[d] || {})) {
      const su = sess.unit || "lbs";
      const v = (sess.exercises || []).reduce((a, ex) => a + (ex.sets || [])
        .filter(s => (s.done === true || (s.done === undefined && parseFloat(s.reps) > 0)) && s.type !== "warmup")
        .reduce((b, s) => b + cvt(parseFloat(s.weight) || 0, su, unit) * (parseFloat(s.reps) || 0), 0), 0);
      const wk = weekKey(new Date(d));
      volByWeek[wk] = (volByWeek[wk] || 0) + v;
    }
  }
  const thisWk = weekKey(new Date());
  const thisWkVol = volByWeek[thisWk] || 0;
  const priorVols = Object.entries(volByWeek).filter(([k]) => k !== thisWk).map(([, v]) => v);
  if (thisWkVol > 0 && priorVols.length >= 2 && thisWkVol > Math.max(...priorVols)) {
    candidates.push({ key: `bigweek:${thisWk}`, priority: 2, icon: "trophy", headline: `Biggest week yet`, sub: `${Math.round(thisWkVol).toLocaleString()} ${unit} lifted this week — a personal best` });
  }

  // 4. Total sessions milestone
  const totalSessions = dates.reduce((a, d) => a + Object.keys(history[d] || {}).length, 0);
  if ([10, 25, 50, 100, 150, 200, 250, 300, 500].includes(totalSessions)) {
    candidates.push({ key: `sessions:${totalSessions}`, priority: 1, icon: "trophy", headline: `${totalSessions} workouts logged`, sub: `That's real consistency. Proud of you.` });
  }

  // 5. Recovery awareness — if the user has trained one muscle group 3+ times in the
  // last 4 days, gently flag it (could use a rest day for that group). Quiet, low-priority
  // so it doesn't dominate when there's better news.
  {
    const sevenDayAgo = now - 4 * DAY;
    const muscleHits = {};
    for (const d of dates) {
      const dms = new Date(d + "T12:00:00").getTime();
      if (dms < sevenDayAgo) continue;
      for (const sess of Object.values(history[d] || {})) {
        const musclesThisSession = new Set();
        (sess.exercises || []).forEach(ex => {
          if (!ex.name) return;
          // Only count if there were real working sets
          const worked = (ex.sets || []).some(s => s.type !== "warmup" && (s.done === true || parseFloat(s.reps) > 0));
          if (!worked) return;
          const m = (getMuscle(ex.name)) || "";
          if (m && m !== "Cardio" && m !== "Yoga") musclesThisSession.add(m);
        });
        musclesThisSession.forEach(m => { muscleHits[m] = (muscleHits[m] || 0) + 1; });
      }
    }
    const overworked = Object.entries(muscleHits).filter(([m, c]) => c >= 3);
    if (overworked.length > 0) {
      const [m, c] = overworked[0];
      candidates.push({ key: `recovery:${m}:${weekKey(new Date())}`, priority: 5, icon: "trending", headline: `${m} trained ${c}× in 4 days`, sub: `Consider a rest day for that group — recovery is where the gains stick.` });
    }
  }

  if (!candidates.length) return returnAll ? [] : null;
  // Drop any insight the user has already swiped away (persisted keys).
  const dismissed = new Set(store.dismissedInsights || []);
  const live = candidates.filter(c => !c.key || !dismissed.has(c.key));
  if (!live.length) return returnAll ? [] : null;
  // Lower priority number = more compelling. Tie-break randomly so it varies.
  live.sort((a, b) => a.priority - b.priority || Math.random() - 0.5);
  return returnAll ? live : live[0];
}

// Returns ALL insight candidates (sorted, most compelling first) for the swipeable
// card stack on the workout tab. Wraps getProgressInsight's collection by exposing
// the internal candidate list via the optional `returnAll` flag.
function getProgressInsights(store, unit) {
  return getProgressInsight(store, unit, true) || [];
}

// Parse rep range like "8-12" or "8–12" or "5,3,1" or "8" → { low, high }
function parseRepRange(reps) {
  if (!reps) return null;
  const s = String(reps).replace(/\s/g,"");
  // Range with dash or en-dash
  const m = s.match(/^(\d+)[–-](\d+)$/);
  if (m) return { low: parseInt(m[1]), high: parseInt(m[2]) };
  // Single number
  const n = parseInt(s);
  if (!isNaN(n) && /^\d+$/.test(s)) return { low: n, high: n };
  return null;
}

// Strength score — rates the user's main lifts relative to bodyweight against population
// standards, returning a level (Untrained→Elite) per lift plus an overall. Uses the same
// Bodyweight-multiple thresholds (lower bound of each level), by sex. These are reasonable,
// transparent population baselines for relative strength — not medical or competitive metrics.
const STRENGTH_STANDARDS_BY_SEX = {
  male: {
    "Barbell Bench Press":     { Novice:0.5, Intermediate:0.75, Advanced:1.25, Elite:1.75 },
    "Barbell Back Squat":      { Novice:0.75, Intermediate:1.25, Advanced:1.75, Elite:2.5 },
    "Deadlift":                { Novice:1.0, Intermediate:1.5, Advanced:2.25, Elite:3.0 },
    "Overhead Press (Barbell)":{ Novice:0.35, Intermediate:0.55, Advanced:0.8, Elite:1.1 },
    "Incline Bench Press":     { Novice:0.4, Intermediate:0.6, Advanced:1.0, Elite:1.45 },
    "Front Squat":             { Novice:0.55, Intermediate:0.95, Advanced:1.4, Elite:2.0 },
    "Barbell Row":             { Novice:0.5, Intermediate:0.75, Advanced:1.1, Elite:1.5 },
    "Romanian Deadlift":       { Novice:0.6, Intermediate:1.0, Advanced:1.6, Elite:2.2 },
    "Hip Thrust":              { Novice:1.0, Intermediate:1.5, Advanced:2.25, Elite:3.0 },
  },
  female: {
    "Barbell Bench Press":     { Novice:0.3, Intermediate:0.5, Advanced:0.8, Elite:1.1 },
    "Barbell Back Squat":      { Novice:0.5, Intermediate:0.9, Advanced:1.35, Elite:1.9 },
    "Deadlift":                { Novice:0.65, Intermediate:1.1, Advanced:1.75, Elite:2.5 },
    "Overhead Press (Barbell)":{ Novice:0.2, Intermediate:0.35, Advanced:0.55, Elite:0.8 },
    "Incline Bench Press":     { Novice:0.25, Intermediate:0.4, Advanced:0.65, Elite:0.95 },
    "Front Squat":             { Novice:0.4, Intermediate:0.7, Advanced:1.1, Elite:1.6 },
    "Barbell Row":             { Novice:0.3, Intermediate:0.5, Advanced:0.75, Elite:1.1 },
    "Romanian Deadlift":       { Novice:0.4, Intermediate:0.75, Advanced:1.2, Elite:1.7 },
    "Hip Thrust":              { Novice:0.75, Intermediate:1.25, Advanced:1.9, Elite:2.6 },
  },
};
const STRENGTH_LIFT_ALIASES = {
  "Barbell Bench Press": ["Bench Press","Flat Barbell Bench","Flat Bench"],
  "Barbell Back Squat": ["Back Squat","Low Bar Squat","High Bar Squat","Squat"],
  "Deadlift": ["Conventional Deadlift","Sumo Deadlift","Trap Bar Deadlift","Hex Bar Deadlift"],
  "Overhead Press (Barbell)": ["Overhead Press","OHP","Standing Barbell OHP","Standing OHP","Standing Press","Strict Press","Military Press","Barbell OHP","Barbell Overhead Press"],
  "Incline Bench Press": ["Incline Barbell Press","Incline Bench","Incline Press"],
  "Front Squat": ["Barbell Front Squat"],
  "Barbell Row": ["Bent-Over Row","Barbell Bent-Over Row","Pendlay Row","Bent Over Barbell Row","BB Row"],
  "Romanian Deadlift": ["RDL","Barbell RDL","Stiff-Leg Deadlift","Stiff Leg Deadlift"],
  "Hip Thrust": ["Barbell Hip Thrust","Glute Bridge","Barbell Glute Bridge"],
};
const STRENGTH_LEVELS = ["Untrained","Novice","Intermediate","Advanced","Elite"];

function levelForRatio(standards, lift, ratio) {
  const s = standards[lift];
  if (!s) return "Untrained";
  if (ratio >= s.Elite) return "Elite";
  if (ratio >= s.Advanced) return "Advanced";
  if (ratio >= s.Intermediate) return "Intermediate";
  if (ratio >= s.Novice) return "Novice";
  return "Untrained";
}

// sex: "male" | "female" | "other". Standards are physiological, so "other" uses the midpoint
// of the male/female thresholds (a neutral baseline) rather than forcing a binary choice.
// Returns { overall, score (0-100), lifts:[{lift, best, ratio, level}], bodyweight, sex } or
// { ready:false } if there isn't enough data (no bodyweight or no main-lift PRs).
function computeStrengthScore(store, unit, sex = "male") {
  let standards;
  if (sex === "other") {
    // Average the male & female thresholds per lift/level for a neutral baseline.
    const m = STRENGTH_STANDARDS_BY_SEX.male, f = STRENGTH_STANDARDS_BY_SEX.female;
    standards = {};
    for (const lift of Object.keys(m)) {
      standards[lift] = {};
      for (const lvl of Object.keys(m[lift])) {
        standards[lift][lvl] = (m[lift][lvl] + f[lift][lvl]) / 2;
      }
    }
  } else {
    standards = STRENGTH_STANDARDS_BY_SEX[sex] || STRENGTH_STANDARDS_BY_SEX.male;
  }
  const bodyLog = [...(store.bodyLog || [])].sort((a, b) => (b.date || "").localeCompare(a.date || ""));
  const bw = bodyLog.length ? parseFloat(bodyLog[0].weight) : null;
  if (!bw || bw <= 0) return { ready: false, reason: "no_bodyweight" };
  const prs = store.prs || {};
  // Normalize for tolerant matching — strips parentheticals like "(heavy)", punctuation, casing.
  const norm = (s) => (s || "").toLowerCase().replace(/\([^)]*\)/g, "").replace(/[^a-z0-9]+/g, " ").trim();
  // Keyword signatures so a PR logged under almost any sensible name still maps to a scored lift.
  // Exclusions prevent double-counting (e.g. incline bench must not also count as flat bench).
  const LIFT_KEYWORDS = {
    "Barbell Bench Press": (n) => n.includes("bench") && !n.includes("incline") && !n.includes("decline") && !n.includes("close grip") && !n.includes("db") && !n.includes("dumbbell"),
    "Barbell Back Squat": (n) => n.includes("squat") && !n.includes("front") && !n.includes("hack") && !n.includes("goblet") && !n.includes("split") && !n.includes("sissy") && !n.includes("bulgarian"),
    "Deadlift": (n) => n.includes("deadlift") && !n.includes("romanian") && !n.includes("rdl") && !n.includes("stiff") && !n.includes("single"),
    "Overhead Press (Barbell)": (n) => (n.includes("overhead press") || n.includes("ohp") || n.includes("military") || (n.includes("strict press")) || (n.includes("shoulder press") && n.includes("barbell"))) && !n.includes("db") && !n.includes("dumbbell") && !n.includes("machine"),
    "Incline Bench Press": (n) => n.includes("incline") && (n.includes("bench") || n.includes("press")) && !n.includes("db") && !n.includes("dumbbell") && !n.includes("machine") && !n.includes("smith"),
    "Front Squat": (n) => n.includes("front squat"),
    "Barbell Row": (n) => (n.includes("barbell row") || n.includes("bent over row") || n.includes("bent-over row") || n.includes("pendlay") || (n.includes("bb row"))) && !n.includes("db") && !n.includes("dumbbell") && !n.includes("cable") && !n.includes("machine") && !n.includes("seated"),
    "Romanian Deadlift": (n) => n.includes("romanian") || n.includes("rdl") || n.includes("stiff leg") || n.includes("stiff-leg"),
    "Hip Thrust": (n) => n.includes("hip thrust") || n.includes("glute bridge"),
  };
  // Strength standards are defined against a 1-REP MAX. store.prs holds the heaviest raw weight
  // lifted (any rep count), which understates strength for higher-rep PRs. So we estimate 1RM
  // from the best set in history per lift (Epley via calc1RM), which is the correct comparison.
  const histUnit = unit;
  const liftBestE1RM = {}; // canonical lift -> best estimated 1RM (in display unit)
  const scanMatch = (name) => {
    for (const canonical of Object.keys(standards)) {
      const kw = LIFT_KEYWORDS[canonical];
      const aliasNames = [canonical, ...(STRENGTH_LIFT_ALIASES[canonical] || [])];
      if (aliasNames.includes(name) || (kw && kw(norm(name)))) return canonical;
    }
    return null;
  };
  for (const d of Object.keys(store.history || {})) {
    for (const sess of Object.values(store.history[d] || {})) {
      const sUnit = sess.unit || histUnit;
      for (const ex of (sess.exercises || [])) {
        if (!ex.name) continue;
        const canonical = scanMatch(ex.name);
        if (!canonical) continue;
        for (const s of (ex.sets || [])) {
          if (s.type === "warmup") continue;
          const done = s.done === true || (s.done === undefined && parseFloat(s.reps || s.r) > 0);
          if (!done) continue;
          const w = parseFloat(s.weight ?? s.w);
          const r = parseInt(s.reps ?? s.r);
          if (!w || !r || r < 1) continue;
          const e1rmRaw = calc1RM(w, r);
          if (!e1rmRaw) continue;
          // Normalize to the display unit used for bodyweight comparison.
          const e1rm = sUnit === unit ? e1rmRaw : cvt(e1rmRaw, sUnit, unit);
          if (!liftBestE1RM[canonical] || e1rm > liftBestE1RM[canonical]) liftBestE1RM[canonical] = e1rm;
        }
      }
    }
  }
  // Fallback: if history has no matching sets but a stored PR exists, use the raw PR (better than
  // nothing — treats it as a 1RM, slightly conservative for high-rep PRs).
  const bestPR = (canonical) => {
    if (liftBestE1RM[canonical]) return liftBestE1RM[canonical];
    const names = [canonical, ...(STRENGTH_LIFT_ALIASES[canonical] || [])];
    const exactVals = names.map(n => prs[n]).filter(v => v != null && v > 0);
    const kw = LIFT_KEYWORDS[canonical];
    const fuzzyVals = kw ? Object.entries(prs).filter(([name, v]) => v != null && v > 0 && kw(norm(name))).map(([, v]) => v) : [];
    // prs are stored in lbs; convert to display unit if needed.
    const all = [...exactVals, ...fuzzyVals].map(v => unit === "lbs" ? v : cvt(v, "lbs", unit));
    return all.length ? Math.max(...all) : null;
  };
  const lifts = [];
  let levelSum = 0, counted = 0;
  for (const lift of Object.keys(standards)) {
    const best = bestPR(lift);
    if (best == null) continue;
    const ratio = best / bw; // both in the same unit, so the ratio is unit-independent
    const level = levelForRatio(standards, lift, ratio);
    lifts.push({ lift, best, ratio: Math.round(ratio * 100) / 100, level });
    levelSum += STRENGTH_LEVELS.indexOf(level);
    counted++;
  }
  if (!counted) return { ready: false, reason: "no_lifts" };
  const avgIdx = levelSum / counted;
  const overall = STRENGTH_LEVELS[Math.round(avgIdx)] || "Untrained";
  const score = Math.round((avgIdx / (STRENGTH_LEVELS.length - 1)) * 100);
  return { ready: true, overall, score, lifts, bodyweight: bw, counted, sex };
}

// Maps each body-map region to the scored lift(s) that best represent its strength. Regions with no
// standard lift (calves, forearms, abs, etc.) are intentionally absent — they render as "no data".
// A few are proxies (biceps via rows, triceps via pressing) since there's no isolation standard.
const MUSCLE_STRENGTH_LIFTS = {
  Chest: ["Barbell Bench Press", "Incline Bench Press"],
  Shoulders: ["Overhead Press (Barbell)"],
  Quads: ["Barbell Back Squat", "Front Squat"],
  Lats: ["Barbell Row", "Deadlift"],
  Hamstrings: ["Romanian Deadlift", "Deadlift"],
  Glutes: ["Hip Thrust", "Barbell Back Squat", "Deadlift", "Romanian Deadlift"],
  Triceps: ["Barbell Bench Press", "Overhead Press (Barbell)"],
  Biceps: ["Barbell Row"],
  Traps: ["Deadlift", "Barbell Row"],
  LowerBack: ["Deadlift", "Romanian Deadlift"],
  "Rear Delts": ["Barbell Row"],
};

// Per-region strength fraction (0 = Untrained, 1 = Elite) vs bodyweight standards, for the weakness
// map. Returns { ready, regionFrac:{Region:0..1}, overall, score } or { ready:false, reason }.
function muscleStrength(store, unit, sex) {
  const ss = computeStrengthScore(store, unit, sex);
  if (!ss.ready) return { ready: false, reason: ss.reason };
  const liftLevel = {};
  ss.lifts.forEach(l => { liftLevel[l.lift] = STRENGTH_LEVELS.indexOf(l.level); });
  const denom = STRENGTH_LEVELS.length - 1;
  const regionFrac = {};
  for (const [region, lifts] of Object.entries(MUSCLE_STRENGTH_LIFTS)) {
    let best = null;
    lifts.forEach(lift => { if (liftLevel[lift] != null) best = Math.max(best == null ? -1 : best, liftLevel[lift]); });
    if (best != null) regionFrac[region] = best / denom;
  }
  return { ready: true, regionFrac, overall: ss.overall, score: ss.score };
}

// Assembles a compact, structured snapshot of the user's training for the AI coach to reason
// over. Deliberately summarized (not raw dumps) to keep the prompt small and focused: recent
// sessions, top lifts + strength levels, stalls, consistency. All from data already stored.
function buildCoachContext(store, unit) {
  const sex = store.strengthSex || "male";
  const ss = computeStrengthScore(store, unit, sex);
  const streak = calcWeeklyStreak(store.workoutDates || {}, store.weeklyTarget || 3);
  const dates = Object.keys(store.history || {}).sort().reverse();
  const recent = [];
  for (const d of dates) {
    const sessions = Object.values(store.history[d] || {});
    for (const s of sessions) {
      const exs = (s.exercises || []).map(ex => {
        const done = (ex.sets || []).filter(st => st.type !== "warmup" && (st.done === true || (st.done === undefined && parseFloat(st.reps) > 0)));
        if (!done.length) return null;
        const top = done.reduce((a, st) => (parseFloat(st.weight) || 0) > (parseFloat(a.weight) || 0) ? st : a, done[0]);
        return { name: ex.name, sets: done.length, topWeight: parseFloat(top.weight) || 0, topReps: parseFloat(top.reps) || 0 };
      }).filter(Boolean);
      if (exs.length) recent.push({ date: d, name: s.dayName || s.name || "Workout", exercises: exs });
    }
    if (recent.length >= 8) break;
  }
  const lastTrained = {};
  const todayMs = new Date(dKey() + "T12:00:00").getTime();
  for (const d of dates) {
    const sessions = Object.values(store.history[d] || {});
    for (const s of sessions) {
      for (const ex of (s.exercises || [])) {
        const m = resolveMuscle(ex.name);
        if (m && lastTrained[m] == null) {
          lastTrained[m] = Math.floor((todayMs - new Date(d + "T12:00:00").getTime()) / 86400000);
        }
      }
    }
  }
  const stalls = [];
  ["Barbell Bench Press","Barbell Back Squat","Deadlift","Overhead Press (Barbell)"].forEach(l => {
    const dl = detectDeloadNeeded(store, l, unit);
    if (dl.stalled) stalls.push({ lift: l, detail: dl.reason });
  });
  return {
    unit, sex,
    strength: ss.ready ? { overall: ss.overall, score: ss.score, lifts: ss.lifts.map(l => ({ lift: l.lift, level: l.level, ratio: l.ratio })) } : null,
    bodyweight: ss.ready ? ss.bodyweight : null,
    consistency: { weeklyStreak: streak.count, thisWeek: streak.thisWeek, target: streak.target },
    recentSessions: recent,
    daysSinceMuscle: lastTrained,
    stalls,
    recovery: store.recovery || null,
  };
}

// Returns the last `limit` working-set sessions for an exercise, newest first.
// Each entry: { date, unit, sets:[{w,r}], daysSince, topWeight, topReps, volume }.
function getExerciseSessions(store, exName, limit = 5) {
  const dates = Object.keys(store.history || {}).sort().reverse();
  const out = [];
  const todayMs = new Date(dKey() + "T12:00:00").getTime();
  for (const d of dates) {
    const sessions = Object.values(store.history[d] || {});
    for (const sess of sessions) {
      const ex = sess.exercises?.find(e => e.name === exName);
      if (!ex) continue;
      const doneSets = (ex.sets || []).filter(s =>
        s.type !== "warmup" &&
        (s.done === true || (s.done === undefined && parseFloat(s.reps) > 0))
      );
      if (!doneSets.length) continue;
      const sets = doneSets.map(s => ({ w: parseFloat(s.weight) || 0, r: parseFloat(s.reps) || 0 }));
      const topWeight = Math.max(...sets.map(s => s.w));
      const topReps = Math.max(...sets.filter(s => s.w === topWeight).map(s => s.r), 0);
      const volume = sets.reduce((a, s) => a + s.w * s.r, 0);
      const dMs = new Date(d + "T12:00:00").getTime();
      out.push({
        date: d, unit: sess.unit || "lbs", sets,
        daysSince: Math.max(0, Math.floor((todayMs - dMs) / 86400000)),
        topWeight, topReps, volume,
      });
      if (out.length >= limit) return out;
    }
  }
  return out;
}

// Deload / stall detection. Looks at the last several sessions of an exercise and flags when
// the lifter has plateaued — i.e. top working weight hasn't increased across 3+ sessions and
// estimated 1RM is flat/declining. Returns { stalled, ... } or { stalled:false }. A planned
// deload (back off ~10%, rebuild) is the standard fix for a stall.
function detectDeloadNeeded(store, exName, unit) {
  const sessions = getExerciseSessions(store, exName, 5);
  if (sessions.length < 3) return { stalled: false };
  const norm = sessions.map(s => ({
    wU: cvt(s.topWeight, s.unit, unit),
    e1rm: s.topWeight ? cvt(s.topWeight, s.unit, unit) * (1 + Math.min(s.topReps, 12) / 30) : 0,
  }));
  const recent = norm.slice(0, 3);
  const topWeights = recent.map(s => s.wU);
  const maxTop = Math.max(...topWeights);
  const minTop = Math.min(...topWeights);
  const weightFlat = (maxTop - minTop) < (unit === "lbs" ? 5 : 2.5);
  const e1rms = recent.map(s => s.e1rm);
  const e1rmNotProgressing = e1rms[0] <= Math.max(e1rms[1], e1rms[2]) + 0.01;
  if (weightFlat && e1rmNotProgressing) {
    const dl = unit === "lbs" ? Math.round((maxTop * 0.9) / 5) * 5 : Math.round((maxTop * 0.9) / 2.5) * 2.5;
    return {
      stalled: true,
      sessions: recent.length,
      topWeight: maxTop,
      deloadWeight: dl,
      reason: `Stalled at ${maxTop} ${unit} for ${recent.length} sessions`,
      suggestion: `Try a deload: drop to ~${dl} ${unit} and rebuild with clean reps`,
    };
  }
  return { stalled: false };
}

// Progressive overload — double progression model
// Returns { type, weight, reps, note, deltaWeight, deltaReps, reason }
function suggestNextSet(store, exName, repsTarget, unit, setIndex = 0) {
  const last = getLastExerciseSession(store, exName);
  if (!last) return null;

  const range = parseRepRange(repsTarget);
  const lastInUserUnit = last.sets.map(s => ({ w: cvt(s.w, last.unit, unit), r: s.r }));
  const setMatch = lastInUserUnit[setIndex] || lastInUserUnit[lastInUserUnit.length - 1];
  if (!setMatch || !setMatch.w) return null;

  const lastWeight = setMatch.w;
  const lastReps = setMatch.r;
  const inc = unit === "lbs" ? 5 : 2.5;

  // Deload if it's been 14+ days
  if (last.daysSince >= 14) {
    const dl = unit === "lbs" ? Math.round((lastWeight * 0.9) / 5) * 5 : Math.round((lastWeight * 0.9) / 2.5) * 2.5;
    return {
      type: "deload",
      weight: dl,
      reps: range ? range.low : lastReps,
      note: "Deload (off " + last.daysSince + "d)",
      deltaWeight: dl - lastWeight,
      reason: "Back after a break — start lighter",
    };
  }

  // Double progression — judged PER-SET against the matching set from last session.
  // Old logic checked `every set hit the range top`, which meant a fatigued last set
  // (e.g. 5 reps on a 6-8 range) blocked the suggestion to add weight on set 1 — even
  // when set 1 cleanly hit 8 last time. Real progression is per-set.
  if (range) {
    const setHitTop = lastReps >= range.high;
    if (setHitTop) {
      // The matching set hit the top of the range last time → add weight.
      // If they went way past the top (e.g. 15 reps on a 5-8 range), bump weight
      // but keep reps realistic instead of dropping all the way to range.low.
      const overshoot = lastReps - range.high;
      if (overshoot >= 4) {
        return {
          type: "weight",
          weight: lastWeight + inc,
          reps: Math.max(range.high, lastReps - 2),
          note: `+${inc} ${unit}`,
          deltaWeight: inc,
          reason: `Way above target reps — add ${inc} ${unit}, keep reps high`,
        };
      }
      return {
        type: "weight",
        weight: lastWeight + inc,
        reps: range.low,
        note: `+${inc} ${unit}`,
        deltaWeight: inc,
        reason: `Hit ${range.high} on this set — add ${inc} ${unit}`,
      };
    } else {
      // Same weight, push for more reps (within the range)
      const target = Math.min(range.high, Math.max(lastReps + 1, range.low));
      return {
        type: "reps",
        weight: lastWeight,
        reps: target,
        note: `same weight`,
        deltaReps: target - lastReps,
        reason: target > lastReps ? `Push for ${target} reps` : `Match last session`,
      };
    }
  }

  // No range: simple bump on +2 reps
  if (lastReps >= 10) {
    return {
      type: "weight",
      weight: lastWeight + inc,
      reps: Math.max(lastReps - 2, 5),
      note: `+${inc} ${unit}`,
      deltaWeight: inc,
      reason: `Strong last time — add ${inc} ${unit}`,
    };
  }
  return {
    type: "match",
    weight: lastWeight,
    reps: lastReps + 1,
    note: `+1 rep`,
    deltaReps: 1,
    reason: `Push for one more rep`,
  };
}

// Haptic helpers - tiered patterns
// Haptic feedback vocabulary
//
// Each `kind` produces a different vibration pattern. The goal is for users
// to start subconsciously associating certain feels with certain actions —
// the way iOS uses crisp/soft/heavy for different interactions.
//
// Web Vibration API takes either a single ms or an array of [vibrate, pause, vibrate, ...].
// Most users on iOS won't feel these (Safari doesn't support navigator.vibrate)
// but Android and Capacitor-wrapped builds will. The patterns degrade gracefully.
function haptic(kind) {
  // Native haptics (iOS/Android) via the Capacitor Haptics plugin, reached through the runtime
  // global so there's no build-time import (keeps the web bundle clean). Real Taptic Engine
  // feedback — far better than web vibration, which iOS Safari/WKWebView ignores entirely.
  try {
    const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
    if (Cap?.isNativePlatform?.() && Cap.Plugins?.Haptics) {
      const H = Cap.Plugins.Haptics;
      const impact = (style) => { try { H.impact({ style }); } catch {} };
      const notify = (type) => { try { H.notification({ type }); } catch {} };
      switch (kind) {
        case "tap": case "lock": case "modal-out": case "back": impact("LIGHT"); break;
        case "light": case "modal-in": case "tab": case "undo": case "refresh": impact("LIGHT"); break;
        case "medium": impact("MEDIUM"); break;
        case "heavy": impact("HEAVY"); break;
        case "complete": notify("SUCCESS"); break;
        case "rest-end": notify("WARNING"); break;
        case "delete": case "warn": notify("WARNING"); break;
        case "error": notify("ERROR"); break;
        case "success": notify("SUCCESS"); break;
        case "pr-small": notify("SUCCESS"); break;
        case "pr": notify("SUCCESS"); break;
        case "pr-big": notify("SUCCESS"); setTimeout(() => notify("SUCCESS"), 130); break;
        default: impact("LIGHT");
      }
      return; // handled natively — don't also fire web vibration
    }
  } catch {}
  try {
    if (!navigator.vibrate) return;
    switch (kind) {
      // ── Standard taps ───────────────────────────────────────────────
      case "tap":      navigator.vibrate(8); break;   // generic button press, very subtle
      case "light":    navigator.vibrate(12); break;  // chip/toggle selection
      case "medium":   navigator.vibrate(20); break;  // set checked (not last)
      case "heavy":    navigator.vibrate(35); break;  // important confirmation

      // ── Workout flow ────────────────────────────────────────────────
      case "complete": navigator.vibrate(28); break;          // last set of exercise done
      case "rest-end": navigator.vibrate([60, 80, 60]); break; // rest timer fires
      case "lock":     navigator.vibrate(6); break;            // swipe-to-done lock detent

      // ── PR celebration — tiered by magnitude ────────────────────────
      case "pr-small": navigator.vibrate([15, 30, 15, 30, 40]); break;            // PR by 0-5%
      case "pr":       navigator.vibrate([20, 40, 20, 40, 80]); break;            // standard PR
      case "pr-big":   navigator.vibrate([25, 30, 25, 30, 25, 30, 120]); break;   // PR by 10%+

      // ── Navigation ──────────────────────────────────────────────────
      case "modal-in":  navigator.vibrate(10); break;  // open a sheet/modal
      case "modal-out": navigator.vibrate(6); break;   // dismiss a sheet/modal
      case "back":      navigator.vibrate(8); break;   // navigate backward
      case "tab":       navigator.vibrate(12); break;  // switch tab

      // ── Destructive ─────────────────────────────────────────────────
      case "delete":   navigator.vibrate([30, 30, 30]); break;     // confirm delete
      case "undo":     navigator.vibrate(12); break;               // undo
      case "warn":     navigator.vibrate([30, 60, 30]); break;     // confirm warning

      // ── Status ──────────────────────────────────────────────────────
      case "success":  navigator.vibrate([15, 30, 30]); break;     // generic success (post sent etc)
      case "error":    navigator.vibrate([40, 60, 40, 60, 40]); break; // operation failed
      case "refresh":  navigator.vibrate([10, 20, 10]); break;     // pull-to-refresh tick

      default:         navigator.vibrate(15);
    }
  } catch {}
}

// ═════════════════════════════════════════════════════════════════════════════
// LOCAL NOTIFICATIONS — native rest-timer alert that fires even when the app is
// backgrounded or the phone is locked. A JS timer can't run in the background on iOS
// (the WebView is suspended), so instead we SCHEDULE a local notification for when the
// rest period ends, and cancel it if rest finishes/cancels early. Reached via the runtime
// Capacitor global so there's no build-time import (keeps the web bundle clean).
// ═════════════════════════════════════════════════════════════════════════════
function nativeLocalNotifs() {
  const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
  if (Cap?.isNativePlatform?.() && Cap.Plugins?.LocalNotifications) return Cap.Plugins.LocalNotifications;
  return null;
}

// API base — on the web the serverless function is served at a relative path; inside a native
// Capacitor build there's no local server, so AI calls must hit the deployed origin in full.
const API_BASE = (() => {
  const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
  return Cap?.isNativePlatform?.() ? "https://spotr-drab.vercel.app" : "";
})();
function aiEndpoint() { return API_BASE + "/api/ai"; }

// ═════════════════════════════════════════════════════════════════════════════
// HEALTHKIT — recovery signals (iOS only, native build). Reads HRV, resting heart
// rate, and last night's sleep so the AI coach can factor recovery into advice.
// Uses the @capgo/capacitor-health plugin (Capacitor 8, SPM). Reached through the
// runtime Capacitor global so the web bundle stays clean and degrades gracefully.
// ═════════════════════════════════════════════════════════════════════════════
function nativeHealth() {
  const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
  if (Cap?.isNativePlatform?.() && Cap.Plugins?.Health) return Cap.Plugins.Health;
  return null;
}
function healthKitAvailable() { return !!nativeHealth(); }

const HK_READ = ["heartRateVariability", "restingHeartRate", "sleep"];

async function requestHealthPermission() {
  const H = nativeHealth();
  if (!H) return false;
  try {
    const avail = await H.isAvailable();
    if (avail && avail.available === false) return false;
    await H.requestAuthorization({ read: HK_READ, write: [] });
    return true;
  } catch (e) {
    return false;
  }
}

// Pull the most recent recovery snapshot. Returns null on web or if unavailable/denied.
// Shape: { hrv: number|null, restingHr: number|null, sleepHours: number|null, capturedAt: iso }
async function readRecovery() {
  const H = nativeHealth();
  if (!H) return null;
  // Must request authorization before reading, or HealthKit silently returns nothing (no popup).
  try {
    const avail = await H.isAvailable();
    if (avail && avail.available === false) return null;
    await H.requestAuthorization({ read: HK_READ, write: [] });
  } catch (e) { /* if the user denies, the reads below just come back empty */ }
  const now = new Date();
  const endIso = now.toISOString();
  const startIso = new Date(now.getTime() - 1000 * 60 * 60 * 36).toISOString(); // last 36h

  async function read(dataType) {
    try {
      const r = await H.readSamples({ dataType, startDate: startIso, endDate: endIso, limit: 200 });
      return (r && r.samples) ? r.samples : [];
    } catch (e) { return []; }
  }

  const out = { hrv: null, restingHr: null, sleepHours: null, capturedAt: endIso };

  // HRV (ms) — average the window
  const hrv = await read("heartRateVariability");
  if (hrv.length) {
    const vals = hrv.map(s => parseFloat(s.value)).filter(v => !isNaN(v));
    if (vals.length) out.hrv = Math.round(vals.reduce((a, b) => a + b, 0) / vals.length);
  }
  // Resting HR (bpm) — most recent
  const rhr = await read("restingHeartRate");
  if (rhr.length) {
    const v = parseFloat(rhr[0].value);
    if (!isNaN(v)) out.restingHr = Math.round(v);
  }
  // Sleep — sum asleep states from the most recent night (samples are in minutes)
  const sleep = await read("sleep");
  if (sleep.length) {
    let mins = 0;
    for (const s of sleep) {
      const st = (s.sleepState || "").toLowerCase();
      const asleep = st === "asleep" || st === "rem" || st === "deep" || st === "light";
      if (asleep) {
        const v = parseFloat(s.value);
        if (!isNaN(v)) mins += v;                       // value is minutes
        else if (s.startDate && s.endDate) mins += (new Date(s.endDate) - new Date(s.startDate)) / 60000;
      }
    }
    if (mins > 0) out.sleepHours = Math.round((mins / 60) * 10) / 10;
  }

  if (out.hrv == null && out.restingHr == null && out.sleepHours == null) return null;
  return out;
}
const REST_NOTIF_ID = 7711; // fixed id so we can reliably cancel/replace the rest notification
let __notifPermAsked = false;
async function ensureNotifPermission() {
  const LN = nativeLocalNotifs();
  if (!LN) return false;
  try {
    const status = await LN.checkPermissions();
    if (status?.display === "granted") return true;
    if (__notifPermAsked) return false; // don't nag if already asked & denied this session
    __notifPermAsked = true;
    const req = await LN.requestPermissions();
    return req?.display === "granted";
  } catch { return false; }
}
// Schedule the "rest is up" notification `seconds` from now. Cancels any prior one first.
async function scheduleRestNotification(seconds) {
  const LN = nativeLocalNotifs();
  if (!LN || !seconds || seconds < 1) return;
  try {
    const ok = await ensureNotifPermission();
    if (!ok) return;
    await LN.cancel({ notifications: [{ id: REST_NOTIF_ID }] }).catch(() => {});
    await LN.schedule({
      notifications: [{
        id: REST_NOTIF_ID,
        title: "Rest's up — back to work",
        body: "Go hit your next set 💪",
        schedule: { at: new Date(Date.now() + seconds * 1000) },
        sound: "default",
      }],
    });
  } catch {}
}
async function cancelRestNotification() {
  const LN = nativeLocalNotifs();
  if (!LN) return;
  try { await LN.cancel({ notifications: [{ id: REST_NOTIF_ID }] }); } catch {}
}

// ═════════════════════════════════════════════════════════════════════════════
// NETWORK STATUS — offline detection. Uses the Capacitor Network plugin for reliable
// native state + change events, falling back to navigator.onLine on web. Drives the
// "you're offline" indicator and (later) the sync-queue flush on reconnect.
// ═════════════════════════════════════════════════════════════════════════════
function nativeNetwork() {
  const Cap = (typeof window !== "undefined") ? window.Capacitor : null;
  if (Cap?.isNativePlatform?.() && Cap.Plugins?.Network) return Cap.Plugins.Network;
  return null;
}
// Subscribe to connectivity changes. Calls cb(isOnline) on every change and once initially.
// Returns an unsubscribe function. Works on web (online/offline events) and native (plugin).
function subscribeNetwork(cb) {
  const N = nativeNetwork();
  if (N) {
    let handle = null;
    try { N.getStatus().then(s => cb(!!s.connected)).catch(() => cb(true)); } catch { cb(true); }
    try { handle = N.addListener("networkStatusChange", (s) => cb(!!s.connected)); } catch {}
    return () => { try { handle?.remove?.(); } catch {} };
  }
  // Web fallback
  const on = () => cb(true), off = () => cb(false);
  try {
    cb(typeof navigator !== "undefined" ? navigator.onLine !== false : true);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
  } catch {}
  return () => { try { window.removeEventListener("online", on); window.removeEventListener("offline", off); } catch {} };
}



